import{_ as r,a as d,b as a}from"./chunks/hub0080-channel-edit-basic.BmNb4UH4.js";import{_ as o,c as n,o as s,ag as e}from"./chunks/framework.XjE0kKti.js";const h="/gatewayweb/docs/assets/hub0041-namespace-list.C3ec2nrB.png",g="/gatewayweb/docs/assets/hub0041-namespace-menu.DAjDGACI.png",x=JSON.parse('{"title":"命名空间管理（hub0041）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0041.md","filePath":"modules/hub0041.md","lastUpdated":null}'),b={name:"modules/hub0041.md"};function l(i,t,u,c,p,m){return s(),n("div",null,[...t[0]||(t[0]=[e('<h1 id="命名空间管理-hub0041" tabindex="-1">命名空间管理（hub0041） <a class="header-anchor" href="#命名空间管理-hub0041" aria-label="Permalink to &quot;命名空间管理（hub0041）&quot;">​</a></h1><p>命名空间用于在某一 <strong>服务中心实例</strong> 下划分逻辑边界，承载 <strong>服务列表</strong>、<strong>配置中心</strong> 等数据的隔离与配额控制。创建命名空间前，请先在 <strong>服务中心实例管理（hub0040）</strong> 中准备好可用的实例。</p><p><img src="'+h+'" alt="命名空间列表与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>命名空间 CRUD</td><td>新建、编辑、查看详情、删除（含批量删除）。</td></tr><tr><td>与实例绑定</td><td>每个命名空间必须关联一个服务中心实例；部署环境随所选实例自动带出且不可手改。</td></tr><tr><td>配额</td><td>可限制命名空间下服务数量、配置数量（0 表示无限制）。</td></tr><tr><td>活动状态</td><td>控制命名空间是否处于可用态（活动 / 非活动）。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>服务治理</strong> → <strong>命名空间管理</strong>。</p><hr><h2 id="列表与筛选" tabindex="-1">列表与筛选 <a class="header-anchor" href="#列表与筛选" aria-label="Permalink to &quot;列表与筛选&quot;">​</a></h2><h3 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命名空间名称</strong></td><td>按名称筛选（占位：请输入命名空间名称）。</td></tr><tr><td><strong>服务中心实例</strong></td><td>通过「…」选择器选择实例，用于只看某实例下的命名空间。</td></tr><tr><td><strong>部署环境</strong></td><td>全部 / 开发环境 / 预发布环境 / 生产环境。</td></tr><tr><td><strong>活动状态</strong></td><td>全部 / 活动 / 非活动。</td></tr></tbody></table><p>使用 <strong>查询</strong> 刷新列表；<strong>重置</strong> 清空条件后重新查询。</p><h3 id="工具栏" tabindex="-1">工具栏 <a class="header-anchor" href="#工具栏" aria-label="Permalink to &quot;工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新建命名空间</strong></td><td>打开「新增命名空间」对话框。</td></tr><tr><td><strong>编辑</strong></td><td>必须在表格中 <strong>勾选且仅勾选一行</strong>，否则会提示「请先选择」或「只能编辑一个命名空间」。</td></tr><tr><td><strong>删除</strong></td><td>支持 <strong>多选勾选</strong> 后批量删除；确认框中会提示删除条数且操作不可恢复。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>与筛选表单一致。</td></tr></tbody></table><hr><h2 id="表格列说明" tabindex="-1">表格列说明 <a class="header-anchor" href="#表格列说明" aria-label="Permalink to &quot;表格列说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>列</th><th>含义</th></tr></thead><tbody><tr><td>命名空间 ID</td><td>唯一标识（主键），可与 SDK、配置中的 <code>namespaceId</code> 对应。</td></tr><tr><td>命名空间名称</td><td>展示用名称，与 ID 均受格式与长度校验（见下文表单说明）。</td></tr><tr><td>服务中心实例</td><td>该命名空间所属实例名称。</td></tr><tr><td>部署环境</td><td>与实例环境一致：开发 / 预发布 / 生产。</td></tr><tr><td>描述</td><td>业务说明文案。</td></tr><tr><td>服务配额 / 配置配额</td><td>上限数字；为 <strong>0</strong> 时在列表中显示为 <strong>无限制</strong>。</td></tr><tr><td>活动状态</td><td>活动 / 非活动。</td></tr><tr><td>创建时间、创建人、修改时间、修改人</td><td>审计信息。</td></tr></tbody></table><hr><h2 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h2><p>在数据行上右键，除 <strong>复制行数据</strong>、<strong>复制单元格</strong> 外，还可：</p><p><img src="'+g+'" alt="命名空间行右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情</strong></td><td>只读对话框，数据从后端拉取最新。</td></tr><tr><td><strong>编辑</strong></td><td>与工具栏编辑等价，针对当前行。</td></tr><tr><td><strong>删除</strong></td><td>删除当前命名空间单行；删除前有确认框。</td></tr></tbody></table><hr><h2 id="新增-编辑-查看命名空间" tabindex="-1">新增 / 编辑 / 查看命名空间 <a class="header-anchor" href="#新增-编辑-查看命名空间" aria-label="Permalink to &quot;新增 / 编辑 / 查看命名空间&quot;">​</a></h2><p>对话框标题：<strong>新增命名空间</strong>、<strong>编辑命名空间</strong>、<strong>查看命名空间详情</strong>。支持最大化；<strong>保存</strong> 提交，<strong>取消</strong> 关闭。</p><h3 id="tab-基本信息" tabindex="-1">Tab：基本信息 <a class="header-anchor" href="#tab-基本信息" aria-label="Permalink to &quot;Tab：基本信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>命名空间 ID</strong></td><td>必填；1～32 位，仅字母、数字、下划线。可不填由系统生成（以界面提示为准）。</td></tr><tr><td><strong>命名空间名称</strong></td><td>必填；同样 1～32 位字母、数字、下划线。</td></tr><tr><td><strong>服务中心实例</strong></td><td>必填；选择后 <strong>部署环境</strong> 会根据实例自动填充且为只读。</td></tr><tr><td><strong>部署环境</strong></td><td>由实例决定，不可编辑。</td></tr><tr><td><strong>命名空间描述</strong></td><td>可选多行文本。</td></tr><tr><td><strong>活动状态</strong></td><td>开关：活动 / 非活动。</td></tr></tbody></table><h3 id="tab-配额配置" tabindex="-1">Tab：配额配置 <a class="header-anchor" href="#tab-配额配置" aria-label="Permalink to &quot;Tab：配额配置&quot;">​</a></h3><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务数量配额限制</strong></td><td>该命名空间下允许注册的最大服务数；<strong>0</strong> 表示无限制。</td></tr><tr><td><strong>配置数量配额限制</strong></td><td>该命名空间下配置条数上限；<strong>0</strong> 表示无限制。</td></tr></tbody></table><h3 id="tab-其它" tabindex="-1">Tab：其它 <a class="header-anchor" href="#tab-其它" aria-label="Permalink to &quot;Tab：其它&quot;">​</a></h3><p>备注、创建/修改时间与操作人（后四项在编辑、查看时多为只读）。</p><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to &quot;使用建议&quot;">​</a></h2><ul><li>先创建 <strong>服务中心实例（hub0040）</strong>，再在本页选择对应实例创建命名空间，避免无实例可选。</li><li>删除命名空间前，确认其下 <strong>服务列表、配置中心</strong> 等数据已迁移或不再需要，避免误删导致业务中断。</li><li><strong>编辑</strong> 依赖表格 <strong>勾选单行</strong>；若只单击高亮而未勾选，工具栏编辑可能无效，请勾选左侧复选框。</li></ul><hr><h2 id="配套-预警渠道-hub0080" tabindex="-1">配套：预警渠道（hub0080） <a class="header-anchor" href="#配套-预警渠道-hub0080" aria-label="Permalink to &quot;配套：预警渠道（hub0080）&quot;">​</a></h2><p>下列界面属于 <strong>预警管理 → 预警服务配置（hub0080）</strong>，与命名空间同属平台治理能力。告警渠道用于发送邮件、钉钉、企业微信等通知；在 <strong>服务中心实例（hub0040）</strong> 的告警 Tab 中配置渠道名称时，会与此处维护的渠道对应。</p><p><img src="'+r+'" alt="预警渠道列表"></p><h3 id="筛选与工具栏" tabindex="-1">筛选与工具栏 <a class="header-anchor" href="#筛选与工具栏" aria-label="Permalink to &quot;筛选与工具栏&quot;">​</a></h3><table tabindex="0"><thead><tr><th>筛选项</th><th>说明</th></tr></thead><tbody><tr><td>渠道名称、渠道类型、启用状态、默认渠道</td><td>与列表列一致，支持组合查询。</td></tr></tbody></table><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增渠道</strong></td><td>打开新增告警渠道配置对话框。</td></tr><tr><td><strong>删除</strong></td><td>删除 <strong>当前单击选中（高亮）</strong> 的一行配置；未点击选中行时会提示先选择。</td></tr><tr><td><strong>查询 / 重置</strong></td><td>刷新列表或清空条件。</td></tr></tbody></table><p>列表中 <strong>启用状态</strong> 列可直接通过开关切换（无需进入编辑对话框）。</p><h3 id="右键菜单-1" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单-1" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p><img src="'+d+'" alt="预警渠道右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>查看详情 / 编辑</strong></td><td>打开对话框查看或修改完整配置。</td></tr><tr><td><strong>复制</strong></td><td>基于当前渠道复制为新配置，<strong>渠道名称需重新填写</strong>。</td></tr><tr><td><strong>重载配置</strong></td><td>使配置立即生效（确认后执行）。</td></tr><tr><td><strong>设为默认</strong></td><td>将未指定渠道时的默认告警出口设为本渠道。</td></tr><tr><td><strong>预警测试</strong></td><td>发送测试消息；<strong>未启用</strong> 的渠道无法测试。</td></tr><tr><td><strong>删除</strong></td><td>删除该渠道配置。</td></tr></tbody></table><h3 id="编辑对话框-基本信息-tab-示例" tabindex="-1">编辑对话框（基本信息 Tab 示例） <a class="header-anchor" href="#编辑对话框-基本信息-tab-示例" aria-label="Permalink to &quot;编辑对话框（基本信息 Tab 示例）&quot;">​</a></h3><p><img src="'+a+'" alt="编辑告警渠道配置 - 基本信息"></p><p>对话框标题为 <strong>新增告警渠道配置</strong> / <strong>编辑告警渠道配置</strong> / <strong>查看告警渠道配置详情</strong>。Tab 包括：</p><ol><li><strong>基本信息</strong>：渠道名称（英文、数字、下划线）、渠道类型、渠道描述、优先级（1～10，数字越小优先级越高）、默认渠道、启用状态、默认模板名称（可「…」选择模板）等。</li><li><strong>渠道配置</strong>：按渠道类型展示 SMTP、Webhook 等分组字段（以界面为准）。</li><li><strong>其他信息</strong>：扩展与审计类字段。</li></ol><p>更完整的字段说明可单独维护在 <a href="./hub0080.html">预警服务配置（hub0080）</a> 文档中。</p>',52)])])}const f=o(b,[["render",l]]);export{x as __pageData,f as default};
